const body = $json.body || $json;
const out = [];
for (const entry of (body.entry || [])) {
  for (const change of (entry.changes || [])) {
    const value = change.value || {};
    const metadata = value.metadata || {};
    for (const msg of (value.messages || [])) {
      if (msg.type !== 'text') continue;
      const text = (msg.text && msg.text.body || '').trim();
      if (!text) continue;
      out.push({
        event_type: 'message', received_at: new Date().toISOString(), message_id: msg.id,
        customer_phone: msg.from,
        customer_name: (value.contacts || []).find(c => c.wa_id === msg.from)?.profile?.name || '',
        message_text: text,
        phone_number_id: metadata.phone_number_id || $env.META_PHONE_NUMBER_ID || '',
        display_phone_number: metadata.display_phone_number || '', raw_message: msg, raw_body: body
      });
    }
  }
}
if (!out.length) return [{ json: { event_type: 'ignored', reason: 'No inbound text messages found', received_at: new Date().toISOString() } }];
return out.map(json => ({ json }));

const msg = ($json.message_text || '').toLowerCase();
const businessName = $env.BUSINESS_NAME || 'TU NEGOCIO';
const faq = [
  { topic: 'horario', keywords: ['horario','abren','cierran','atienden'], answer: `El horario de ${businessName} es: {{EDITAR_HORARIO}}.` },
  { topic: 'precio', keywords: ['precio','cuesta','costo','tarifa','vale'], answer: 'Los precios dependen del servicio/producto. Te puedo orientar y, si hace falta, te paso con una persona del equipo.' },
  { topic: 'ubicacion', keywords: ['ubicación','ubicacion','dirección','direccion','donde','local'], answer: `La ubicación de ${businessName} es: {{EDITAR_DIRECCION}}.` },
  { topic: 'agenda', keywords: ['cita','reservar','agenda','turno','consulta'], answer: 'Puedo ayudarte a avanzar. Dime qué necesitas, para cuándo y tu nombre.' },
  { topic: 'humano', keywords: ['asesor','persona','humano','ejecutivo','llamar','llamada'], answer: 'Claro. Te paso con una persona del equipo para ayudarte mejor.' }
];
const matches = faq.filter(row => row.keywords.some(k => msg.includes(k)));
const urgencyWords = ['urgente','hoy','ahora','emergencia','problema','queja','reclamo','cancelar','devolución','devolucion'];
const wantsHuman = matches.some(m => m.topic === 'humano') || urgencyWords.some(w => msg.includes(w));
return [{ json: { ...$json, business_name: businessName, faq_matches: matches, faq_context: matches.map(m => `Tema: ${m.topic}\nRespuesta base: ${m.answer}`).join('\n\n'), needs_owner_handoff_seed: wantsHuman } }];

const schema = { response_text: 'Respuesta en español lista para enviar por WhatsApp. Máximo 900 caracteres.', lead_stage: 'nuevo|calificado|necesita_humano|no_fit', lead_name: 'Nombre si el cliente lo dio; si no, vacío.', lead_need: 'Necesidad principal detectada.', urgency: 'baja|media|alta', handoff_required: 'boolean', handoff_reason: 'Motivo si requiere dueño/humano.', missing_info: ['Dato que conviene pedir después'] };
const system = `Eres el agente de WhatsApp de ${$json.business_name}. Responde como asistente comercial práctico para una PYME. No inventes precios, garantías, disponibilidad ni políticas. Si falta información, pide un solo dato claro. Si hay reclamo, urgencia, solicitud de humano, negociación compleja o tema sensible, marca handoff_required=true. Devuelve SOLO JSON válido con esta forma: ${JSON.stringify(schema)}.`;
const user = `Mensaje del cliente: ${$json.message_text}

Nombre detectado: ${$json.customer_name || 'No disponible'}
Teléfono: ${$json.customer_phone}

FAQ/base disponible:
${$json.faq_context || 'Sin coincidencias exactas. Usa una respuesta general y pide el siguiente dato útil.'}

Si no estás seguro, no inventes. Responde breve y orientado a avanzar la conversación.`;
return [{ json: { ...$json, openai_payload: { model: $env.OPENAI_MODEL || 'gpt-4o-mini', temperature: 0.2, response_format: { type: 'json_object' }, messages: [ { role: 'system', content: system }, { role: 'user', content: user } ] } } }];

let ai = {};
try { const content = $json.choices?.[0]?.message?.content || $json.body?.choices?.[0]?.message?.content || ''; ai = typeof content === 'string' ? JSON.parse(content) : content; }
catch (e) { ai = { response_text: 'Gracias por escribirnos. Para ayudarte bien, dime por favor qué necesitas y tu nombre.', lead_stage: 'nuevo', urgency: 'media', handoff_required: true, handoff_reason: 'No se pudo interpretar la respuesta del modelo', missing_info: ['necesidad', 'nombre'] }; }
const original = $('Structured FAQ / Knowledge Base').item.json;
const text = String(ai.response_text || '').slice(0, 900).trim() || 'Gracias por escribirnos. ¿Me dices qué necesitas para poder ayudarte?';
const handoff = Boolean(ai.handoff_required) || Boolean(original.needs_owner_handoff_seed);
return [{ json: { ...original, ai, response_text: text, lead_stage: ai.lead_stage || 'nuevo', lead_name: ai.lead_name || original.customer_name || '', lead_need: ai.lead_need || '', urgency: ai.urgency || 'media', handoff_required: handoff, handoff_reason: ai.handoff_reason || (original.needs_owner_handoff_seed ? 'Cliente pidió humano o usó palabra sensible' : '') } }];

